    61|    if (mem && typeof mem.usedJSHeapSize === 'number') {
    62|      const toMb = (b?: number): number | null => (typeof b === 'number' ? Math.round((b / (1024 * 1024)) * 10) / 10 : null);
    63|      return {
    64|        usedMb: toMb(mem.usedJSHeapSize),
    65|        totalMb: toMb(mem.totalJSHeapSize),
