    78| * JS thread, so frame deltas directly reflect JS-thread responsiveness:
    79| * - fps      = frames rendered in the last 1s window (achieved frame rate).
    80| * - jsFps    = 1000 / worst frame delta in the window (worst-case jank signal).
    81| * - dropped  = frames slower than ~1.5× the target frame budget.
    82| */
    83|function useFpsSampler(active: boolean): FpsSample {
    84|  const [sample, setSample] = useState<FpsSample>({ fps: 0, jsFps: 0, worstFrameMs: 0, droppedFrames: 0 });
    85|  const frameTimesRef = useRef<number[]>([]);
    86|  const lastTsRef = useRef<number | null>(null);
    87|  const rafRef = useRef<number | null>(null);
    88|  const lastReportRef = useRef<number>(0);
    89|
    90|  useEffect(() => {
    91|    if (!active) return;
    92|    let mounted = true;
    93|
    94|    const tick = (ts: number): void => {
    95|      if (!mounted) return;
    96|      const last = lastTsRef.current;
    97|      if (last !== null) {
    98|        const delta = ts - last;
    99|        if (delta > 0 && delta < 2000) {
   100|          frameTimesRef.current.push(delta);
   101|        }
   102|      }
   103|      lastTsRef.current = ts;
   104|
   105|      // Trim to a rolling ~1s window by total elapsed time.
   106|      let total = 0;
   107|      const times = frameTimesRef.current;
   108|      for (let i = times.length - 1; i >= 0; i -= 1) {
   109|        total += times[i];
   110|        if (total > FPS_WINDOW_MS) {
   111|          frameTimesRef.current = times.slice(i);
   112|          break;
   113|        }
   114|      }
   115|
   116|      if (ts - lastReportRef.current >= 250) {
   117|        lastReportRef.current = ts;
   118|        const window = frameTimesRef.current;
   119|        if (window.length > 0) {
   120|          const sum = window.reduce((a, b) => a + b, 0);
   121|          const fps = Math.min(120, Math.round((window.length / sum) * 1000));
   122|          const worst = Math.max(...window);
   123|          const jsFps = Math.min(120, Math.round(1000 / worst));
   124|          const dropped = window.filter((d) => d > DROPPED_FRAME_MS).length;
   125|          setSample({ fps, jsFps, worstFrameMs: Math.round(worst * 10) / 10, droppedFrames: dropped });
   126|        }
   127|      }
   128|
   129|      rafRef.current = requestAnimationFrame(tick);
   130|    };
   131|
   132|    rafRef.current = requestAnimationFrame(tick);
   133|    return () => {
   134|      mounted = false;
   135|      if (rafRef.current !== null) {
