          />
          <Row icon={<Fingerprint size={14} color={Colors.gold} />} label="User ID" value={userId ?? 'null'} testId="diag-user-id" />
          <Row icon={<Shield size={14} color={Colors.gold} />} label="Role" value={userRole ?? 'null'} testId="diag-role" />
